mapper.select:
SELECT COUNT(BOARD_SEQ) FROM NMCP_BOARD_BAS WHERE 1=1
AND (UPPER(BOARD_SUBJECT) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!' OR UPPER(BOARD_CONTENTS) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!')
AND BOARD_CTG_SEQ = #{boardCtgSeq}
AND SBST_CTG = #{sbstCtg}
AND VIEW_YN = 'Y' ORDER BY BOARD_SEQ DESC

SELECT RNUM ,BOARD_CTG_SEQ ,SBST_CTG ,BOARD_SEQ ,BOARD_SUBJECT ,BOARD_CONTENTS ,BOARD_WRITER_NM ,BOARD_WRITE_DT ,BOARD_ATT_YN ,SBST_SUB_CTG_CD ,CRET_DT ,CHAR_DT ,IMG_NM FROM ( SELECT ROW_NUMBER () OVER (ORDER BY BAS.CRET_DT ASC) AS RNUM ,BAS.BOARD_CTG_SEQ ,BAS.SBST_CTG ,BAS.BOARD_SEQ ,BAS.BOARD_SUBJECT ,BAS.BOARD_CONTENTS ,BAS.BOARD_WRITER_NM ,BAS.BOARD_WRITE_DT ,BAS.BOARD_ATT_YN ,BAS.SBST_SUB_CTG_CD ,BAS.CRET_DT ,TO_CHAR(BAS.CRET_DT,'YYYY.MM.DD') AS CHAR_DT ,ATT.FILE_PATH_NM AS IMG_NM FROM NMCP_BOARD_BAS BAS LEFT OUTER JOIN ( SELECT AA.ATT_SEQ AS ATT_SEQ , AA.FILE_PATH_NM AS FILE_PATH_NM , AA.FILE_TYPE AS FILE_TYPE , AA.FILE_CAPA AS FILE_CAPA , AA.BOARD_SEQ FROM NMCP_BOARD_ATT_DTL AA, ( SELECT MAX (ATT_SEQ) AS ATT_SEQ, BOARD_SEQ FROM NMCP_BOARD_ATT_DTL GROUP BY BOARD_SEQ ) BB WHERE AA.ATT_SEQ = BB.ATT_SEQ AND AA.BOARD_SEQ = BB.BOARD_SEQ ) ATT ON BAS.BOARD_SEQ = ATT.BOARD_SEQ WHERE 1=1
AND (UPPER(BAS.BOARD_SUBJECT) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!' OR UPPER(BAS.BOARD_CONTENTS) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!')
AND BAS.BOARD_CTG_SEQ = #{boardCtgSeq}
AND BAS.SBST_CTG = #{sbstCtg}
AND BAS.VIEW_YN = 'Y' ) ORDER BY CRET_DT DESC

SELECT BOARD_SEQ , BOARD_CTG_SEQ , SBST_CTG , SBST_SUB_CTG_CD , BOARD_SUBJECT , BOARD_WRITER_NM , BOARD_CONTENTS , NOTI_YN , VIEW_YN , IMG_NM , BOARD_WRITE_DT , BOARD_ATT_YN , CRET_DT , CHAR_DT , NEXT_SEQ , NEXT_SUBJECT , NEXT_DT , PRE_SEQ , PRE_SUBJECT , PRE_DT
FROM ( SELECT BOARD_SEQ, BOARD_CTG_SEQ, SBST_CTG, SBST_SUB_CTG_CD, BOARD_SUBJECT, BOARD_CONTENTS, BOARD_WRITER_NM, NOTI_YN, IMG_NM, VIEW_YN, BOARD_WRITE_DT, TO_CHAR(CRET_DT, 'YYYY.MM.DD') AS CHAR_DT, BOARD_ATT_YN, CRET_DT, lead(BOARD_SEQ,1) over (order by CRET_DT) NEXT_SEQ, lead(BOARD_SUBJECT,1,'다음글이 없습니다.') over (order by CRET_DT) NEXT_SUBJECT, lead(CRET_DT,1,'') over (order by CRET_DT) NEXT_DT, lag(BOARD_SEQ,1) over (order by CRET_DT) PRE_SEQ, lag(BOARD_SUBJECT,1,'이전글이 없습니다.') over (order by CRET_DT) PRE_SUBJECT, lag(CRET_DT,1,'') over (order by CRET_DT) PRE_DT FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = #{boardCtgSeq}
AND (UPPER(BOARD_SUBJECT) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!' OR UPPER(BOARD_CONTENTS) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!')
AND SBST_CTG = #{sbstCtg}
AND SBST_SUB_CTG_CD = #{sbstSubCtgCd}
AND VIEW_YN = 'Y' ORDER BY CRET_DT DESC ) WHERE BOARD_SEQ = #{boardSeq}
